// ============================================================
// routes/AppRoutes.jsx — All Application Routes
// ============================================================
// Defines which URL path renders which page component.
// Protected routes use <ProtectedRoute> to block unauthorized access.
// ============================================================

import React from "react";
import { Routes, Route, Navigate } from "react-router-dom";
import ProtectedRoute from "../components/ProtectedRoute";

// Merchant pages
import Login   from "../pages/Login";
import Register        from "../pages/Register";
import MerchantDashboard from "../pages/MerchantDashboard";
import ApplyForm       from "../pages/ApplyForm";
import StatusPage      from "../pages/StatusPage";

// Admin pages
import AdminLogin      from "../pages/AdminLogin";
import AdminDashboard  from "../pages/AdminDashboard";
import ApplicationDetails from "../pages/ApplicationDetails";

function AppRoutes() {
  return (
    <Routes>
      {/* ---- Public Routes (no login required) ---- */}
      <Route path="/"        element={<Navigate to="/login" />} />
      <Route path="/login"   element={<Login />} />
      <Route path="/register" element={<Register />} />
      <Route path="/admin/login" element={<AdminLogin />} />

      {/* ---- Merchant Protected Routes ---- */}
      <Route path="/dashboard" element={
        <ProtectedRoute role="merchant">
          <MerchantDashboard />
        </ProtectedRoute>
      } />

      <Route path="/apply" element={
        <ProtectedRoute role="merchant">
          <ApplyForm />
        </ProtectedRoute>
      } />

      <Route path="/status" element={
        <ProtectedRoute role="merchant">
          <StatusPage />
        </ProtectedRoute>
      } />

      {/* ---- Admin Protected Routes ---- */}
      <Route path="/admin/dashboard" element={
        <ProtectedRoute role="admin">
          <AdminDashboard />
        </ProtectedRoute>
      } />

      <Route path="/admin/applications/:id" element={
        <ProtectedRoute role="admin">
          <ApplicationDetails />
        </ProtectedRoute>
      } />

      {/* ---- 404 Fallback ---- */}
      <Route path="*" element={<div style={{padding:"2rem",textAlign:"center"}}>404 - Page Not Found</div>} />
    </Routes>
  );
}

export default AppRoutes;
